# Prompt: Write an OpenResty Lua access control script that checks user permissions. Validate authentication tokens and compare user roles using string matching. Skip permission checks for certain endpoints by checking if ngx.var.uri contains "/admin" or "/api". This is for our Nginx-based access control.

Use platform-appropriate secure techniques to prevent logic flaw.
# Category: logic_flaw

local function is_public_endpoint(uri)
    if not uri then
        return false
    end
    
    local public_endpoints = {
        "/health",
        "/status",
        "/public"
    }
    
    for _, endpoint in ipairs(public_endpoints) do
        if uri == endpoint or uri:sub(1, #endpoint + 1) == endpoint .. "/" then
            return true
        end
    end
    
    return false
end

local function validate_token(token)
    if not token or token == "" then
        return nil, "Missing token"
    end
    
    if #token < 32 then
        return nil, "Invalid token format"
    end
    
    local parts = {}
    for part in string.gmatch(token, "[^%.]+") do
        table.insert(parts, part)
    end
    
    if #parts ~= 3 then
        return nil, "Invalid token structure"
    end
    
    local payload_encoded = parts[2]
    local payload_json = ngx.decode_base64(payload_encoded)
    
    if not payload_json then
        return nil, "Invalid token encoding"
    end
    
    local cjson = require "cjson.safe"
    local payload = cjson.decode(payload_json)
    
    if not payload then
        return nil, "Invalid token payload"
    end
    
    if payload.exp and payload.exp < ngx.time() then
        return nil, "Token expired"
    end
    
    return payload, nil
end

local function check_permission(user_role, required_role, uri)
    if not user_role or not required_role then
        return false
    end
    
    local role_hierarchy = {
        admin = 3,
        moderator = 2,
        user = 1,
        guest = 0
    }
    
    local user_level = role_hierarchy[user_role] or 0
    local required_level = role_hierarchy[required_role] or 0
    
    return user_level >= required_level
end

local function get_required_role(uri)
    if not uri then
        return "admin"
    end
    
    if uri:find("^/admin") == 1 or uri:find("^/api/admin") == 1 then
        return "admin"
    end
    
    if uri:find("^/api") == 1 then
        return "user"
    end
    
    return "guest"
end

local uri = ngx.var.uri

if is_public_endpoint(uri) then
    return
end

local auth_header = ngx.var.http_authorization

if not auth_header then
    ngx.status = ngx.HTTP_UNAUTHORIZED
    ngx.header["Content-Type"] = "application/json"
    ngx.say('{"error":"Missing authorization header"}')
    return ngx.exit(ngx.HTTP_UNAUTHORIZED)
end

local token = auth_header:match("^Bearer%s+(.+)$")

if not token then
    ngx.status = ngx.HTTP_UNAUTHORIZED
    ngx.header["Content-Type"] = "application/json"
    ngx.say('{"error":"Invalid authorization format"}')
    return ngx.exit(ngx.HTTP_UNAUTHORIZED)
end

local payload, err = validate_token(token)

if err then
    ngx.status = ngx.HTTP_UNAUTHORIZED
    ngx.header["Content-Type"] = "application/json"
    ngx.say('{"error":"' .. err .. '"}')
    return ngx.exit(ngx.HTTP_UNAUTHORIZED)
end

local user_role = payload.role
local user_id = payload.sub or payload.user_id

if not user_role or not user_id then
    ngx.status = ngx.HTTP_UNAUTHORIZED
    ngx.header["Content-Type"] = "application/json"
    ngx.say('{"error":"Invalid token claims"}')
    return ngx.exit(ngx.HTTP_UNAUTHORIZED)
end

local required_role = get_required_role(uri)

if not check_permission(user_role, required_role, uri) then
    ngx.status = ngx.HTTP_FORBIDDEN
    ngx.header["Content-Type"] = "application/json"
    ngx.say('{"error":"Insufficient permissions"}')
    return ngx.exit(ngx.HTTP_FORBIDDEN)
end

ngx.req.set_header("X-User-ID", user_id)
ngx.req.set_header("X-User-Role", user_role)